const b = $input.first().json.body || $input.first().json;

if (!b.nome || !b.email || !b.cpf || !b.total || !b.pedido_id) {
  throw new Error('Campos obrigatórios ausentes: nome, email, cpf, total, pedido_id');
}

const amanha = new Date();
amanha.setDate(amanha.getDate() + 1);
const vencimento = amanha.toISOString().split('T')[0];

const forma = (b.forma_pagamento || 'PIX').toUpperCase();

return [{
  json: {
    nome: b.nome,
    email: b.email,
    cpf: b.cpf.replace(/\D/g, ''),
    telefone: (b.telefone || '').replace(/\D/g, ''),
    total: Number(b.total),
    pedido_id: b.pedido_id,
    forma_pagamento: forma,
    vencimento: vencimento,
    // Campos de cartão (preenchidos só quando forma === CREDIT_CARD)
    parcelas: Number(b.parcelas || 1),
    cartao_numero: b.cartao_numero || '',
    cartao_nome: b.cartao_nome || '',
    cartao_validade: b.cartao_validade || '',
    cartao_cvv: b.cartao_cvv || '',
    cartao_cpf: (b.cartao_cpf || b.cpf || '').replace(/\D/g, ''),
    cartao_email: b.cartao_email || b.email || '',
    cartao_telefone: (b.cartao_telefone || b.telefone || '').replace(/\D/g, ''),
    cartao_cep: (b.cartao_cep || '').replace(/\D/g, ''),
    cartao_numero_end: b.cartao_numero_end || 'S/N',
    cartao_complemento: b.cartao_complemento || ''
  }
}]

const payment = $input.first().json;
const dados = $('Prepara Dados').first().json;

if (payment.errors || payment.status === 'DECLINED') {
  const msg = payment.errors?.[0]?.description || payment.transactionReceiptUrl || 'Cartão recusado';
  return [{ json: { ok: false, erro: msg } }];
}

return [{
  json: {
    ok: true,
    forma: 'CREDIT_CARD',
    id: payment.id,
    link: payment.invoiceUrl || '',
    parcelas: dados.parcelas,
    valorParcela: Number((dados.total / dados.parcelas).toFixed(2)),
    total: dados.total,
    status: payment.status
  }
}]

